import { useState } from "react";
import api from "../../services/api";
import useDashboard from "../../services/useDashboard";
import PageShell, { C, Card, SectionLabel, PrimaryBtn, FInput } from "../Dashboard/PageShell.jsx";

const GRADE = {
  A: { color: C.good, bg: `${C.good}0f`, border: `${C.good}44`, label: "Easily Affordable"  },
  B: { color: C.good, bg: `${C.good}0f`, border: `${C.good}44`, label: "Affordable"          },
  C: { color: C.warn, bg: `${C.warn}0f`, border: `${C.warn}44`, label: "Plan Carefully"      },
  D: { color: C.warn, bg: `${C.warn}0f`, border: `${C.warn}44`, label: "Risky"               },
  F: { color: C.bad,  bg: `${C.bad}0f`,  border: `${C.bad}44`,  label: "Not Recommended"     },
};

const fmtRs = (n) => `Rs.${Number(n).toLocaleString()}`;

export default function AffordabilityChecker() {
  const { data, loading, error } = useDashboard();
  const [form, setForm]     = useState({ itemName: "", itemCost: "", itemType: "depreciating" });
  const [result, setResult] = useState(null);
  const [checking, setChecking] = useState(false);

  const health  = data?.financialHealth;
  const hasData = health?.dataState === "complete";
  const metrics = health?.metrics ?? {};

  const handleCheck = async (e) => {
    e.preventDefault();
    if (!hasData) return;
    setChecking(true); setResult(null);
    try {
      const { data: res } = await api.post("/reports/afford", { itemName: form.itemName, itemCost: Number(form.itemCost), itemType: form.itemType });
      setResult(res);
    } catch (err) { alert(err.response?.data?.message || "Failed to check affordability."); }
    finally { setChecking(false); }
  };

  if (loading) return <PageShell title="Can I Afford This?"><p style={{ color: `${C.beige}cc`, fontSize: "0.95rem" }}>Loading...</p></PageShell>;
  if (error)   return <PageShell title="Can I Afford This?"><Card><p style={{ color: C.bad }}>{error}</p></Card></PageShell>;
  if (!hasData) return (
    <PageShell title="Can I Afford This?">
      <Card style={{ textAlign: "center", padding: "2.5rem" }}>
        <p style={{ color: "#3d5248", fontSize: "0.95rem", lineHeight: 1.6 }}>{health?.dataState === "partial_data" ? "Income data required. Add your monthly income first." : "No financial data found. Add income and expenses first."}</p>
      </Card>
    </PageShell>
  );

  const cfg = result ? GRADE[result.grade] || GRADE.F : null;

  return (
    <PageShell title="Can I Afford This?" subtitle="Get an honest affordability assessment based on your real financial data.">

      {/* Context bar */}
      <div style={{ display: "flex", gap: "1rem", flexWrap: "wrap", background: "rgba(247,244,213,0.18)", padding: "0.85rem 1.1rem", borderRadius: "10px", marginBottom: "1.25rem", border: `1px solid ${C.moss}44` }}>
        {[
          { label: "Income",         value: fmtRs(metrics.monthlyIncome) },
          { label: "Expenses",       value: fmtRs(metrics.monthlyExpenses) },
          { label: "Net savings",    value: fmtRs(metrics.monthlySavings) },
          { label: "Emergency Fund", value: metrics.emergencyFundProvided && metrics.emergencyFundMonths != null ? `${Number(metrics.emergencyFundMonths).toFixed(1)} months` : "No data provided" },
        ].map(item => (
          <div key={item.label} style={{ whiteSpace: "nowrap" }}>
            <span style={{ color: `${C.beige}cc`, fontSize: "0.8rem", fontWeight: "600" }}>{item.label}: </span>
            <strong style={{ color: C.beige, fontSize: "0.9rem", fontWeight: "800" }}>{item.value}</strong>
          </div>
        ))}
      </div>

      {/* Form */}
      <Card style={{ marginBottom: "1.5rem" }}>
        <form onSubmit={handleCheck} style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap", alignItems: "flex-end" }}>
          <div style={{ flex: "2 1 200px" }}>
            <FInput label="Item Name" placeholder='e.g. iPhone 15, Laptop' value={form.itemName} onChange={e => setForm({ ...form, itemName: e.target.value })} />
          </div>
          <div style={{ flex: "1 1 140px" }}>
            <FInput label="Cost (Rs.)" type="number" min="1" placeholder="e.g. 80000" value={form.itemCost} onChange={e => setForm({ ...form, itemCost: e.target.value })} required />
          </div>
          <div style={{ flex: "1 1 160px", display: "flex", flexDirection: "column", gap: "0.3rem" }}>
            <label style={{ fontSize: "0.72rem", fontWeight: "600", color: C.muted, textTransform: "uppercase", letterSpacing: "0.4px" }}>Type</label>
            <select value={form.itemType} onChange={e => setForm({ ...form, itemType: e.target.value })} style={{ padding: "0.7rem 1rem", borderRadius: "10px", border: `1.5px solid ${C.moss}33`, fontSize: "0.92rem", color: C.darkGreen, background: "rgba(247,244,213,0.65)", fontFamily: "inherit" }}>
              <option value="depreciating">Depreciating</option>
              <option value="asset">Asset</option>
              <option value="experience">Experience</option>
            </select>
          </div>
          <PrimaryBtn disabled={checking} style={{ flexShrink: 0, alignSelf: "flex-end" }}>{checking ? "Checking..." : "Check"}</PrimaryBtn>
        </form>
      </Card>

      {result && cfg && (
        <>
          {/* Grade card */}
          <div style={{ background: cfg.bg, border: `1px solid ${cfg.border}`, borderRadius: "14px", padding: "1.5rem", marginBottom: "1.5rem" }}>
            <div style={{ display: "flex", gap: "1.25rem", alignItems: "flex-start", marginBottom: "0.75rem" }}>
              <div style={{ width: "56px", height: "56px", borderRadius: "12px", border: `2px solid ${cfg.color}`, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "800", fontSize: "1.8rem", color: cfg.color, flexShrink: 0 }}>{result.grade}</div>
              <div style={{ flex: 1 }}>
                <p style={{ fontWeight: "700", fontSize: "1.05rem", color: cfg.color, margin: 0 }}>{result.presentVerdict}</p>
                {result.futureVerdict && <p style={{ fontWeight: "600", fontSize: "0.9rem", color: cfg.color, margin: "0.3rem 0 0" }}>{result.futureVerdict}</p>}
                <p style={{ color: "#0f2818", lineHeight: 1.65, margin: "0.45rem 0 0", fontSize: "0.94rem" }}>{result.advice}</p>
              </div>
            </div>
            <p style={{ fontSize: "0.86rem", fontStyle: "italic", margin: 0, paddingTop: "0.75rem", borderTop: `1px solid ${cfg.color}33`, color: "#1a3024", lineHeight: 1.55 }}>{result.typeNote}</p>
          </div>

          {/* Snapshot */}
          <Card>
            <SectionLabel>Financial Snapshot</SectionLabel>
            <p style={{ color: "#4a5c54", fontSize: "0.8rem", margin: "0 0 1rem", lineHeight: 1.5 }}>Based on {result.financials.monthsOfData} month{result.financials.monthsOfData !== 1 ? "s" : ""} of data · Savings: {fmtRs(result.financials.monthlySavings)}/mo</p>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "0.75rem" }}>
              {[
                { label: "Monthly Income",    value: fmtRs(result.financials.monthlyIncome) },
                { label: "Monthly Expenses",  value: fmtRs(result.financials.monthlyExpenses) },
                { label: "Monthly Savings",   value: fmtRs(result.financials.monthlySavings) },
                { label: `Liquid Savings (${result.financials.liquidSavingsLabel})`, value: fmtRs(result.financials.liquidSavings) },
                { label: "Emergency Fund Needed (3mo)", value: fmtRs(result.financials.emergencyFundNeeded) },
                { label: "Safe to Spend",     value: fmtRs(result.financials.safeToSpend), highlight: true },
                {
                  label: "EF After Purchase",
                  value: result.financials.emergencyMonthsAfterPurchase > 0 ? `${result.financials.emergencyMonthsAfterPurchase} months` : result.financials.purchaseShortfall > 0 ? `0 months (${fmtRs(result.financials.purchaseShortfall)} shortfall)` : "0 months",
                  color: result.financials.emergencyMonthsAfterPurchase < 1 ? C.bad : result.financials.emergencyMonthsAfterPurchase < 3 ? C.warn : C.good,
                },
              ].map(s => (
                <div key={s.label} style={{ background: s.highlight ? `${C.moss}18` : "rgba(10,51,35,0.06)", border: s.highlight ? `1px solid ${C.moss}44` : "1px solid rgba(10,51,35,0.08)", padding: "0.75rem", borderRadius: "8px" }}>
                  <p style={{ color: "#3d5248", fontSize: "0.72rem", margin: 0, textTransform: "uppercase", letterSpacing: "0.35px", fontWeight: "700" }}>{s.label}</p>
                  <p style={{ fontWeight: "800", fontSize: "0.96rem", margin: "0.25rem 0 0", color: s.color || "#0a2818" }}>{s.value}</p>
                </div>
              ))}
            </div>

            {result.safeToSpendNote && (
              <div style={{ marginTop: "1rem", background: "rgba(10,51,35,0.06)", border: `1px solid ${C.moss}33`, padding: "0.8rem 1rem", borderRadius: "8px", color: "#2a3d34", fontSize: "0.86rem", lineHeight: 1.65, fontWeight: "500" }}>{result.safeToSpendNote}</div>
            )}

            {result.financials.monthsToSave && (
              <div style={{ marginTop: "1rem", background: "rgba(212,168,67,0.14)", border: `1px solid ${C.warn}55`, padding: "0.8rem 1rem", borderRadius: "8px", color: "#5c4510", fontSize: "0.9rem", lineHeight: 1.55, fontWeight: "600" }}>
                {result.grade === "C"
                  ? <>If not yet saved, it will take <strong>{result.financials.monthsToSave} month{result.financials.monthsToSave > 1 ? "s" : ""}</strong> at {fmtRs(result.financials.monthlySavings)}/mo to accumulate safely.</>
                  : <>Wait <strong>{result.financials.monthsToSave} month{result.financials.monthsToSave > 1 ? "s" : ""}</strong> at {fmtRs(result.financials.monthlySavings)}/mo to buy without touching your emergency fund.{result.financials.monthsToSave > 12 ? " Consider a cheaper alternative." : ""}</>
                }
              </div>
            )}
          </Card>
        </>
      )}
    </PageShell>
  );
}
