import { useEffect, useState } from "react";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";
import api from "../../services/api";
import { useAuth } from "../../context/AuthContext";
import PageShell, { C, Card, SectionLabel, PrimaryBtn, FInput } from "../Dashboard/PageShell.jsx";

ChartJS.register(ArcElement, Tooltip, Legend);

const ASSETS = {
  equity: { label: "Equity", color: C.moss, note: "Stocks + index funds" },
  debt:   { label: "Debt",   color: C.good, note: "Bonds, fixed income"  },
  gold:   { label: "Gold",   color: C.warn, note: "Inflation hedge"       },
  cash:   { label: "Cash",   color: C.muted,note: "Liquid savings"        },
};

const PROFILES = {
  Conservative: { color: C.good, risk: "Low Risk",    horizon: "1–3 years" },
  Moderate:     { color: C.moss, risk: "Medium Risk",  horizon: "5–7 years" },
  Aggressive:   { color: C.bad,  risk: "High Risk",    horizon: "7+ years"  },
};

export default function Portfolio() {
  const { user } = useAuth();
  const [portfolio,    setPortfolio]    = useState(null);
  const [form,         setForm]         = useState({ riskProfile: "Moderate", investmentAmount: "" });
  const [loading,      setLoading]      = useState(true);
  const [generating,   setGenerating]   = useState(false);
  const [error,        setError]        = useState("");
  const [showDetail,   setShowDetail]   = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState(null);

  useEffect(() => {
    if (user?._id) {
      api.get(`/portfolio/${user._id}`).then(r => setPortfolio(r.data)).catch(() => setPortfolio(null)).finally(() => setLoading(false));
    } else { setLoading(false); }
  }, [user]);

  const handleGenerate = async (e) => {
    e.preventDefault(); setError("");
    const amount = Number(form.investmentAmount);
    if (!amount || amount <= 0) { setError("Enter a valid investment amount greater than 0."); return; }
    if (amount < 1000)          { setError("Minimum investment amount is Rs.1,000."); return; }
    setGenerating(true);
    try {
      const { data } = await api.post("/portfolio/generate", { riskProfile: form.riskProfile, investmentAmount: amount });
      setPortfolio(data); setAiSuggestion(null);
    } catch (err) { setError(err.response?.data?.message || "Could not generate portfolio."); }
    finally { setGenerating(false); }
  };

  const handleAISuggest = async () => {
    if (!portfolio) return;
    try {
      const { data } = await api.post("/portfolio/ai-suggest", { riskProfile: portfolio.riskProfile, investmentAmount: portfolio.investmentAmount, recommendedAssets: portfolio.recommendedAssets });
      setAiSuggestion(data);
    } catch { setError("AI service unavailable. Try again later."); }
  };

  const assets       = portfolio?.recommendedAssets || {};
  const assetEntries = Object.entries(assets).filter(([, v]) => v > 0);
  const totalInvested= assetEntries.reduce((a, [, v]) => a + v, 0);

  const chartData = assetEntries.length > 0 ? {
    labels: assetEntries.map(([k]) => ASSETS[k]?.label || k),
    datasets: [{ data: assetEntries.map(([, v]) => v), backgroundColor: assetEntries.map(([k]) => ASSETS[k]?.color || C.muted), borderWidth: 2, borderColor: C.beige }],
  } : null;

  return (
    <PageShell title="Portfolio Recommendation" subtitle="Generate a personalized asset allocation based on your risk profile.">

      {/* Profile selector */}
      <Card style={{ marginBottom: "1.5rem" }}>
        <SectionLabel>Risk Profile</SectionLabel>
        <div style={{ display: "flex", gap: "0.75rem", marginBottom: "1.25rem", flexWrap: "wrap" }}>
          {Object.entries(PROFILES).map(([profile, cfg]) => (
            <div key={profile} onClick={() => setForm({ ...form, riskProfile: profile })} style={{ flex: 1, minWidth: "120px", padding: "1rem", borderRadius: "12px", border: `2px solid ${form.riskProfile === profile ? cfg.color : `${C.moss}22`}`, background: form.riskProfile === profile ? `${cfg.color}12` : `${C.darkGreen}06`, cursor: "pointer", textAlign: "center", transition: "all 0.2s" }}>
              <p style={{ fontWeight: "700", fontSize: "0.95rem", color: cfg.color, margin: "0 0 0.2rem" }}>{profile}</p>
              <p style={{ color: C.muted, fontSize: "0.78rem", margin: "0 0 0.1rem" }}>{cfg.risk}</p>
              <p style={{ color: C.muted, fontSize: "0.72rem", margin: 0 }}>Horizon: {cfg.horizon}</p>
            </div>
          ))}
        </div>
        <form onSubmit={handleGenerate} style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap", alignItems: "flex-end" }}>
          <div style={{ flex: 1, minWidth: "240px" }}>
            <FInput label="Investment Amount (Rs.) — minimum Rs.1,000" type="number" min="1000" placeholder="e.g. 50000" value={form.investmentAmount} onChange={e => { setForm({ ...form, investmentAmount: e.target.value }); setError(""); }} required />
          </div>
          <PrimaryBtn disabled={generating} style={{ flexShrink: 0, alignSelf: "flex-end" }}>{generating ? "Generating..." : "Generate Portfolio"}</PrimaryBtn>
        </form>
        {error && <p style={{ color: C.bad, fontSize: "0.85rem", marginTop: "0.75rem", background: `${C.bad}0f`, padding: "0.6rem 0.9rem", borderRadius: "8px", border: `1px solid ${C.bad}33` }}>{error}</p>}
      </Card>

      {loading && <p style={{ color: `${C.beige}66` }}>Loading portfolio...</p>}

      {!loading && !portfolio && !generating && (
        <Card style={{ textAlign: "center", padding: "2.5rem" }}>
          <p style={{ color: C.muted }}>No portfolio yet. Select a risk profile and enter an amount above to get started.</p>
        </Card>
      )}

      {portfolio && (
        <Card style={{ marginBottom: "1.5rem" }}>
          {/* Header */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1.25rem" }}>
            <div>
              <p style={{ fontWeight: "700", fontSize: "1.1rem", color: C.darkGreen, margin: 0 }}>{portfolio.riskProfile} Portfolio</p>
              <p style={{ color: C.muted, fontSize: "0.85rem", margin: "0.2rem 0 0" }}>Total: Rs.{totalInvested.toLocaleString()}</p>
            </div>
            <span style={{ padding: "0.3rem 0.9rem", borderRadius: "999px", fontWeight: "600", fontSize: "0.82rem", background: `${PROFILES[portfolio.riskProfile]?.color}18`, color: PROFILES[portfolio.riskProfile]?.color }}>{PROFILES[portfolio.riskProfile]?.risk}</span>
          </div>

          {/* Chart + asset list */}
          <div style={{ display: "flex", gap: "2rem", alignItems: "flex-start", flexWrap: "wrap", marginBottom: "1.25rem" }}>
            {chartData && <div style={{ width: "200px", flexShrink: 0 }}><Pie data={chartData} options={{ plugins: { legend: { display: false } } }} /></div>}
            <div style={{ flex: 1, minWidth: "200px" }}>
              {assetEntries.map(([key, amount]) => {
                const cfg = ASSETS[key] || { label: key, color: C.muted, note: "" };
                const pct = totalInvested > 0 ? ((amount / totalInvested) * 100).toFixed(1) : 0;
                return (
                  <div key={key} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0.6rem 0", borderBottom: `1px solid ${C.moss}15` }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
                      <div style={{ width: "10px", height: "10px", borderRadius: "50%", background: cfg.color, flexShrink: 0 }} />
                      <div>
                        <p style={{ fontWeight: "600", color: C.darkGreen, fontSize: "0.88rem", margin: 0 }}>{cfg.label}</p>
                        {cfg.note && <p style={{ color: C.muted, fontSize: "0.7rem", margin: "0.1rem 0 0" }}>{cfg.note}</p>}
                      </div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <p style={{ fontWeight: "700", color: C.darkGreen, margin: 0, fontSize: "0.92rem" }}>Rs.{amount.toLocaleString()}</p>
                      <p style={{ color: C.muted, fontSize: "0.72rem", margin: "0.1rem 0 0" }}>{pct}%</p>
                    </div>
                  </div>
                );
              })}
              <div style={{ display: "flex", justifyContent: "space-between", paddingTop: "0.75rem" }}>
                <span style={{ fontWeight: "700", color: C.darkGreen }}>Total</span>
                <span style={{ fontWeight: "700", color: C.darkGreen }}>Rs.{totalInvested.toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* Rationale */}
          {(portfolio.keyPoints?.length > 0 || portfolio.explanation) && (
            <div style={{ background: `${C.darkGreen}06`, border: `1px solid ${C.moss}22`, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1rem" }}>
              <p style={{ fontWeight: "600", color: C.darkGreen, fontSize: "0.85rem", margin: "0 0 0.5rem" }}>Why this allocation?</p>
              {portfolio.keyPoints?.length > 0 && (
                <ul style={{ margin: "0 0 0.5rem", paddingLeft: "1.25rem" }}>
                  {portfolio.keyPoints.map((pt, i) => <li key={i} style={{ color: C.darkGreen, fontSize: "0.86rem", lineHeight: 1.6, marginBottom: "0.2rem" }}>{pt}</li>)}
                </ul>
              )}
              {portfolio.explanation && (
                <>
                  <button style={{ background: "none", border: "none", color: C.moss, cursor: "pointer", fontSize: "0.8rem", fontWeight: "600", padding: 0, fontFamily: "inherit" }} onClick={() => setShowDetail(d => !d)}>
                    {showDetail ? "Hide details" : "Show full explanation"}
                  </button>
                  {showDetail && <p style={{ color: C.darkGreen, fontSize: "0.86rem", lineHeight: 1.7, margin: "0.75rem 0 0", paddingTop: "0.75rem", borderTop: `1px solid ${C.moss}22` }}>{portfolio.explanation}</p>}
                </>
              )}
            </div>
          )}

          {/* Context */}
          {portfolio.profileContext && (
            <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap", marginBottom: "1rem" }}>
              {[
                { label: "Expected Return", value: portfolio.profileContext.expectedReturn },
                { label: "Risk Level",      value: portfolio.profileContext.riskLevel },
                { label: "Horizon",         value: PROFILES[portfolio.riskProfile]?.horizon },
                portfolio.profileContext.wasPersonalized ? { label: "Personalized", value: "Yes", color: C.moss } : null,
              ].filter(Boolean).map(item => (
                <div key={item.label} style={{ flex: 1, minWidth: "110px", background: `${C.darkGreen}06`, padding: "0.75rem 1rem", borderRadius: "8px" }}>
                  <p style={{ color: C.muted, fontSize: "0.72rem", margin: 0, textTransform: "uppercase", letterSpacing: "0.3px" }}>{item.label}</p>
                  <p style={{ fontWeight: "700", color: item.color || C.darkGreen, margin: "0.2rem 0 0", fontSize: "0.92rem" }}>{item.value}</p>
                </div>
              ))}
            </div>
          )}

          {/* Base vs adjusted */}
          {portfolio.profileContext?.wasPersonalized && portfolio.profileContext.baseAllocation && (
            <div style={{ background: `${C.darkGreen}06`, border: `1px solid ${C.moss}22`, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1rem" }}>
              <SectionLabel>Base vs Adjusted Allocation</SectionLabel>
              {Object.entries(portfolio.profileContext.baseAllocation).map(([asset, basePct]) => {
                const adjPct = portfolio.profileContext.adjustedAllocation?.[asset] ?? basePct;
                const diff   = adjPct - basePct;
                const cfg    = ASSETS[asset] || { label: asset, color: C.muted };
                return (
                  <div key={asset} style={{ display: "flex", alignItems: "center", gap: "0.5rem", fontSize: "0.86rem", marginBottom: "0.35rem" }}>
                    <div style={{ width: "8px", height: "8px", borderRadius: "50%", background: cfg.color }} />
                    <span style={{ flex: 1, color: C.darkGreen }}>{cfg.label}</span>
                    <span style={{ color: C.muted, minWidth: "32px", textAlign: "right" }}>{basePct}%</span>
                    <span style={{ color: C.muted, fontSize: "0.78rem" }}>→</span>
                    <span style={{ fontWeight: "700", minWidth: "48px", color: diff > 0 ? C.bad : diff < 0 ? C.good : C.muted }}>
                      {adjPct}%{diff !== 0 && <span style={{ fontSize: "0.7rem", marginLeft: "0.2rem" }}>({diff > 0 ? "+" : ""}{diff}%)</span>}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          <PrimaryBtn onClick={handleAISuggest} style={{ background: C.darkGreen, color: C.beige }}>Get AI Suggestion</PrimaryBtn>

          {portfolio.disclaimer && (
            <div style={{ background: `${C.warn}0f`, border: `1px solid ${C.warn}33`, padding: "0.75rem 1rem", borderRadius: "8px", marginTop: "1rem" }}>
              <p style={{ color: C.warn, fontSize: "0.82rem", margin: 0, lineHeight: 1.5 }}>{portfolio.disclaimer}</p>
            </div>
          )}

          {portfolio.rebalanceTimeline?.length > 0 && (
            <div style={{ background: `${C.darkGreen}06`, border: `1px solid ${C.moss}22`, padding: "1rem 1.25rem", borderRadius: "10px", marginTop: "1.25rem" }}>
              <SectionLabel>Rebalance Roadmap</SectionLabel>
              {portfolio.rebalanceTimeline.map((step, i) => (
                <div key={i} style={{ display: "flex", gap: "0.75rem", marginBottom: "0.9rem", alignItems: "flex-start" }}>
                  <div style={{ width: "22px", height: "22px", borderRadius: "50%", background: C.moss, color: C.darkGreen, fontSize: "0.7rem", fontWeight: "700", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: "2px" }}>{i+1}</div>
                  <div>
                    <p style={{ fontWeight: "700", color: C.moss, fontSize: "0.82rem", margin: 0 }}>{step.when}</p>
                    <p style={{ color: C.darkGreen, fontSize: "0.86rem", margin: "0.15rem 0 0" }}>{step.action}</p>
                    <p style={{ color: C.muted, fontSize: "0.8rem", margin: "0.1rem 0 0", fontStyle: "italic" }}>{step.then}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </Card>
      )}

      {aiSuggestion && (
        <Card>
          <SectionLabel>AI Next Steps</SectionLabel>
          {aiSuggestion.efSafe === false && (
            <div style={{ background: `${C.bad}0f`, border: `1px solid ${C.bad}44`, color: C.bad, padding: "0.75rem 1rem", borderRadius: "8px", marginBottom: "1rem", fontWeight: "600", fontSize: "0.86rem" }}>
              Emergency fund below 3 months — equity increase recommendations are blocked until resolved.
            </div>
          )}
          {[
            { label: "Priority Action",    value: aiSuggestion.nextAction },
            { label: "Timeline",           value: aiSuggestion.timeline },
            { label: "When to Rebalance",  value: aiSuggestion.rebalanceTrigger },
          ].filter(s => s.value).map(s => (
            <div key={s.label} style={{ marginBottom: "0.9rem" }}>
              <p style={{ color: C.muted, fontSize: "0.72rem", fontWeight: "700", textTransform: "uppercase", letterSpacing: "0.4px", margin: "0 0 0.25rem" }}>{s.label}</p>
              <p style={{ color: C.darkGreen, fontSize: "0.88rem", lineHeight: 1.6, margin: 0 }}>{s.value}</p>
            </div>
          ))}
          {aiSuggestion.efSafe !== false && aiSuggestion.suggestedAdjustment && Object.keys(aiSuggestion.suggestedAdjustment).length > 0 && (
            <div style={{ marginTop: "0.75rem" }}>
              <p style={{ color: C.muted, fontSize: "0.72rem", fontWeight: "700", textTransform: "uppercase", letterSpacing: "0.4px", margin: "0 0 0.4rem" }}>Suggested Amounts</p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}>
                {Object.entries(aiSuggestion.suggestedAdjustment).map(([k, v]) => (
                  <span key={k} style={{ background: `${C.moss}18`, color: C.moss, padding: "0.3rem 0.7rem", borderRadius: "6px", fontSize: "0.84rem", fontWeight: "600" }}>
                    {ASSETS[k]?.label || k}: Rs.{Number(v).toLocaleString()}
                  </span>
                ))}
              </div>
            </div>
          )}
        </Card>
      )}
    </PageShell>
  );
}
