import { useEffect, useState, useCallback } from "react";
import api from "../../services/api";
import PageShell, { C, Card, SectionLabel, PrimaryBtn } from "../Dashboard/PageShell.jsx";

// ── Severity config — no emojis
const SEV = {
  critical: { border: `${C.bad}44`,  bg: `${C.bad}0f`,  color: C.bad,  label: "Critical" },
  high:     { border: `${C.warn}44`, bg: `${C.warn}0f`, color: C.warn, label: "High"     },
  medium:   { border: `${C.warn}33`, bg: `${C.warn}08`, color: C.warn, label: "Medium"   },
  low:      { border: `${C.moss}44`, bg: `${C.moss}0f`, color: C.moss, label: "Info"     },
  good:     { border: `${C.good}44`, bg: `${C.good}0f`, color: C.good, label: "Good"     },
};

const buildAlerts = (m) => {
  const efProvided = m.emergencyFundProvided;
  const ef = m.emergencyFundMonths != null ? +m.emergencyFundMonths : null;
  const sr = m.savingsRatio != null ? +m.savingsRatio : null;
  const dti = m.debtToIncome != null ? +m.debtToIncome : null;
  const inv = m.investmentRatio != null ? +m.investmentRatio : null;
  const mi = +(m.monthlyIncome ?? 0);
  const ms = +(m.monthlyNetSavings ?? m.monthlySavings ?? 0);
  const me = +(m.monthlyExpenses ?? 0);
  const spr = m.spendingRatio != null ? +m.spendingRatio : (mi > 0 ? me / mi : null);

  const issues = [], positives = [];
  const foundationStable = efProvided && ef != null && ef >= 3 && dti != null && dti <= 0.30;
  const isOverspending = spr != null && spr >= 0.80;
  const isCriticalSpend = spr != null && spr >= 0.90;
  const spendLabel = m.spendingRatioDisplayLabel || (spr != null ? `${(spr * 100).toFixed(1)}%` : null);

  if (m.extremeSpendingWarning) {
    issues.push({ severity: "high", title: "Spending vs income", message: m.extremeSpendingWarning, action: "Confirm entries are monthly totals; target expenses under 70% of income when realistic.", blocking: false });
  }

  if (!efProvided) {
    issues.push({ severity: "high", title: "Emergency fund — no data", message: "Add your Emergency Fund Balance (₹) under My Financial Data. Months of cover are not guessed from other entries.", action: "Open My Financial Data and save your current emergency cash balance.", blocking: true });
  } else if (ef != null && ef < 3) {
    const rupees = m.emergencyFundRupees != null ? m.emergencyFundRupees : ef * me;
    const efTarget = me * 3;
    const efGap = Math.max(0, efTarget - rupees);
    const months = ms > 0 && efGap > 0 ? Math.ceil(efGap / ms) : null;
    issues.push({ severity: ef < 1 ? "critical" : "high", title: ef < 1 ? "Emergency Fund — Critical" : "Emergency Fund — Low", message: `${ef.toFixed(1)} months of expenses covered. Minimum recommended: 3 months.`, action: `Target Rs.${Math.round(efTarget).toLocaleString()}. Gap Rs.${Math.round(efGap).toLocaleString()}.${months ? ` ~${months} mo at current net savings.` : ""}`, blocking: true });
  } else if (ef != null) {
    positives.push({ severity: ef < 6 ? "medium" : "good", title: ef < 6 ? "Emergency Fund — OK" : "Emergency Fund — Strong", message: `${ef.toFixed(1)} months on file.`, action: ef < 6 ? "Aim for 6 months." : "Well covered." });
  }

  if (spr != null && isCriticalSpend) {
    const excess = me > 0 ? Math.round(me - mi * 0.70) : 0;
    issues.push({ severity: "critical", title: "Overspending", message: `Spending ${spendLabel} of income on expenses (display may cap at >500%).`, action: excess > 0 ? `Cut ~Rs.${excess.toLocaleString()}/mo to approach 70% of income.` : "Reduce non-essential expenses; check for duplicate or one-off entries counted as monthly." });
  } else if (spr != null && isOverspending) {
    const excess = me > 0 ? Math.round(me - mi * 0.70) : 0;
    issues.push({ severity: "high", title: "High spending ratio", message: `${spendLabel} of income to expenses.`, action: excess > 0 ? `Target Rs.${excess.toLocaleString()}/mo lower spend toward under 70%.` : "Aim below 70% of income." });
  } else if (spr != null && spr > 0.70) {
    issues.push({ severity: "medium", title: "Spending ratio elevated", message: `${spendLabel} of income to expenses.`, action: "Increase emergency fund to at least 3 months of expenses and trim discretionary costs." });
  }

  if (dti != null) {
    if (dti > 0.50) issues.push({ severity: "critical", title: "Debt — Dangerous", message: `${(dti * 100).toFixed(1)}% of income to debt.`, action: "Pay minimums; stop new debt; attack highest interest first." });
    else if (dti > 0.35) issues.push({ severity: "high", title: "Debt — High", message: `${(dti * 100).toFixed(1)}% DTI (safe ~20%).`, action: mi > 0 ? `~Rs.${Math.round((dti - 0.20) * mi).toLocaleString()}/mo above comfort.` : "Reduce debt load." });
    else if (dti > 0.20) issues.push({ severity: "medium", title: "Debt — Elevated", message: `${(dti * 100).toFixed(1)}% DTI.`, action: "Pay extra when possible." });
    else if (dti > 0) positives.push({ severity: "low", title: "Debt — Within guideline", message: `${(dti * 100).toFixed(1)}% DTI — under common 20% reference.`, action: "Keep payments steady; avoid new high-interest debt." });
  }

  if (sr != null) {
    if (sr < 0.05) issues.push({ severity: "critical", title: "Net savings — Critical", message: `Net savings (after debt) are ${(sr * 100).toFixed(1)}% of income.`, action: mi > 0 ? `Aim for Rs.${Math.round(mi * 0.05).toLocaleString()}/mo minimum net.` : "Cut expenses or debt." });
    else if (sr < 0.20) issues.push({ severity: sr < 0.10 ? "high" : "medium", title: "Net savings — Low", message: `${(sr * 100).toFixed(1)}% net (target 20%).`, action: mi > 0 ? `Increase net by ~Rs.${Math.round((0.20 - sr) * mi).toLocaleString()}/mo.` : "" });
    else positives.push({ severity: "low", title: "Net savings — Meets target", message: `${(sr * 100).toFixed(1)}% of income after expenses & debt.`, action: sr >= 0.30 ? "Maintain; align surplus with EF, debt, and investments." : "Consider building toward ~30% if goals need more cushion." });
  }

  if (inv != null) {
    if (!foundationStable && inv > 0) {
      const shouldPause = isCriticalSpend || (isOverspending && ef != null && ef < 1);
      if (shouldPause) issues.push({ severity: "high", title: "Investments vs safety", message: `Investing ${(inv * 100).toFixed(1)}% while foundation is shaky.`, action: "Build EF and control spend before raising investments." });
      else if (ef != null && ef < 3) issues.push({ severity: "medium", title: "Investments — wait", message: "Emergency fund under 3 months on file.", action: "Prioritize cash buffer." });
    } else if (foundationStable) {
      if (inv === 0) positives.push({ severity: "low", title: "Consider investing", message: "Foundation stable.", action: mi > 0 ? `Start ~Rs.${Math.round(mi * 0.05).toLocaleString()}/mo.` : "" });
      else if (inv < 0.10) positives.push({ severity: "low", title: "Investments", message: `${(inv * 100).toFixed(1)}% of income.`, action: "Work toward 10%+ long term once EF ≥3 months and DTI is controlled." });
      else positives.push({ severity: "low", title: "Investments", message: `${(inv * 100).toFixed(1)}% of income.`, action: "Stay diversified; review allocation and fees yearly." });
    }
  }

  return { issues, positives };
};

function AlertCard({ alert, id, expanded, onToggle }) {
  const cfg = SEV[alert.severity] || SEV.low;
  return (
    <div style={{ ...as.card, background: cfg.bg, border: `1px solid ${cfg.border}` }}>
      <div style={as.header}>
        <span style={{ ...as.title, color: C.darkGreen }}>{alert.title}</span>
        <span style={{ ...as.badge, color: cfg.color, background: `${cfg.color}22`, border: `1px solid ${cfg.color}44` }}>{cfg.label}</span>
      </div>
      <p style={as.msg}>{alert.message}</p>
      {alert.action && (
        <>
          {!expanded && <p style={{ ...as.hint, color: cfg.color }}>{alert.action}</p>}
          <button style={{ ...as.expandBtn, color: cfg.color }} onClick={() => onToggle(id)}>
            {expanded ? "Hide" : "Details"}
          </button>
          {expanded && <p style={as.expanded}>{alert.action}</p>}
        </>
      )}
    </div>
  );
}

const as = {
  card:      { padding: "1.1rem 1.25rem", borderRadius: "10px", marginBottom: "0.75rem" },
  header:    { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.35rem", gap: "0.5rem" },
  title:     { fontWeight: "700", fontSize: "0.92rem", lineHeight: 1.35 },
  badge:     { fontSize: "0.7rem", padding: "0.2rem 0.5rem", borderRadius: "6px", fontWeight: "700", flexShrink: 0 },
  msg:       { fontSize: "0.88rem", lineHeight: "1.55", color: "#1e3d2f", margin: "0.2rem 0 0.4rem" },
  hint:      { fontSize: "0.83rem", fontWeight: "600", margin: "0.3rem 0", color: "#1a3328" },
  expandBtn: { background: "none", border: "none", cursor: "pointer", fontSize: "0.78rem", fontWeight: "700", padding: 0, textDecoration: "underline", textUnderlineOffset: "2px" },
  expanded:  { marginTop: "0.6rem", fontSize: "0.86rem", lineHeight: "1.6", color: "#1e3d2f", borderTop: "1px solid rgba(10,51,35,0.12)", paddingTop: "0.6rem" },
};

export default function AIInsights() {
  const [health,    setHealth]    = useState(null);
  const [loading,   setLoading]   = useState(true);
  const [refreshing,setRefreshing]= useState(false);
  const [expanded,  setExpanded]  = useState({});
  const [showPos,   setShowPos]   = useState(false);
  const [authError, setAuthError] = useState(false);

  const fetch = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true); else setLoading(true);
    setAuthError(false);
    try {
      const { data: h } = await api.get("/financial/health");
      setHealth(h);
    } catch (err) {
      if (err.response?.status === 401) setAuthError(true);
      setHealth(null);
    } finally { setLoading(false); setRefreshing(false); }
  }, []);

  useEffect(() => { fetch(); }, [fetch]);

  const toggle = (key) => setExpanded(p => ({ ...p, [key]: !p[key] }));

  const renderBody = () => {
    if (loading) return <p style={{ color: `${C.beige}cc`, padding: "2rem 0", fontSize: "0.95rem" }}>Loading insights...</p>;

    if (authError) return (
      <Card>
        <p style={{ color: C.bad, fontWeight: "600", marginBottom: "0.5rem" }}>Session expired.</p>
        <PrimaryBtn onClick={() => { localStorage.removeItem("token"); window.location.href = "/login"; }}>Log in again</PrimaryBtn>
      </Card>
    );

    if (!health) return (
      <Card>
        <p style={{ color: C.muted, marginBottom: "0.75rem" }}>Could not load insights.</p>
        <PrimaryBtn onClick={() => fetch()}>Retry</PrimaryBtn>
      </Card>
    );

    const m = health.metrics || {};
    const { issues, positives } = buildAlerts(m);
    const spr = m.spendingRatio != null ? +m.spendingRatio : (m.monthlyIncome > 0 ? (m.monthlyExpenses ?? 0) / m.monthlyIncome : null);
    let topPriority = health.biggestWeakness, topDetail = health.biggestWeaknessDetail;
    if (spr != null && spr >= 0.90) { topPriority = "Overspending"; topDetail = `Spending ${(spr * 100).toFixed(1)}% of income is the root cause. Fix spending first.`; }
    else if (spr != null && spr >= 0.80 && health.biggestWeakness === "Emergency Fund") { topPriority = "High Spending"; topDetail = `Spending ${(spr * 100).toFixed(1)}% limits room to build savings.`; }

    const efMo = m.emergencyFundMonths;
    const efVal = m.emergencyFundProvided && efMo != null ? `${efMo.toFixed(1)} mo` : "No data";
    const sr = m.savingsRatio;
    const dti = m.debtToIncome;

    const metrics = [
      { label: "Emergency Fund", val: efVal, good: efMo != null && efMo >= 3, warn: efMo != null && efMo >= 1 },
      { label: "Net savings %", val: sr != null ? `${(sr * 100).toFixed(1)}%` : "—", good: sr != null && sr >= 0.20, warn: sr != null && sr >= 0.10 },
      { label: "Debt-to-Income", val: dti != null ? `${(dti * 100).toFixed(1)}%` : "—", good: dti != null && dti <= 0.20, warn: dti != null && dti <= 0.35, invert: true },
      { label: "Spending Ratio", val: spr != null ? `${(spr * 100).toFixed(1)}%` : "—", good: spr != null && spr <= 0.75, warn: spr != null && spr <= 0.90, invert: true },
    ];

    return (
      <>
        {/* Top priority */}
        {topPriority && topPriority !== "None" && (
          <Card style={{ marginBottom: "1.25rem", borderLeft: `4px solid ${C.warn}` }}>
            <SectionLabel>Top Priority</SectionLabel>
            <p style={{ fontWeight: "700", fontSize: "1rem", color: C.darkGreen, margin: "0 0 0.3rem" }}>{topPriority}</p>
            {topDetail && <p style={{ fontSize: "0.9rem", color: "#2d4a3a", margin: 0, lineHeight: 1.65 }}>{topDetail}</p>}
          </Card>
        )}

        {/* Issues banner */}
        {issues.length > 0 && (
          <div
            style={{
              padding: "0.85rem 1.15rem",
              borderRadius: "10px",
              marginBottom: "1.25rem",
              fontWeight: "600",
              fontSize: "0.92rem",
              lineHeight: 1.5,
              background: "rgba(247,244,213,0.96)",
              border: `1px solid ${issues.some(i => i.severity === "critical") ? C.bad : C.warn}55`,
              color: issues.some(i => i.severity === "critical") ? "#7a241c" : "#5c4a0a",
              boxShadow: "0 2px 12px rgba(10,51,35,0.08)",
            }}
          >
            {issues.length} issue{issues.length > 1 ? "s" : ""} need{issues.length === 1 ? "s" : ""} your attention.
          </div>
        )}

        {/* Issues */}
        {issues.length > 0 && (
          <>
            <SectionLabel onDark>Issues to Address</SectionLabel>
            {issues.map((a, i) => <AlertCard key={i} alert={a} id={`issue-${i}`} expanded={!!expanded[`issue-${i}`]} onToggle={toggle} />)}
          </>
        )}

        {issues.length === 0 && (
          <div style={{ padding: "1rem 1.25rem", borderRadius: "10px", background: "rgba(76,175,125,0.14)", border: `1px solid ${C.good}55`, marginBottom: "1.25rem" }}>
            <p style={{ color: "#1e5c38", fontWeight: "700", margin: 0 }}>No critical issues found.</p>
            <p style={{ color: "#245a3a", fontSize: "0.9rem", margin: "0.3rem 0 0", lineHeight: 1.55 }}>Your financial foundation is in good shape.</p>
          </div>
        )}

        {/* Positives toggle */}
        {positives.length > 0 && (
          <>
            <button type="button" style={{ width: "100%", padding: "0.65rem", background: "rgba(247,244,213,0.12)", border: `1px solid ${C.moss}55`, borderRadius: "10px", cursor: "pointer", color: `${C.beige}ee`, fontWeight: "600", marginBottom: "0.75rem", fontSize: "0.88rem", fontFamily: "inherit" }} onClick={() => setShowPos(p => !p)}>
              {showPos ? "Hide" : "Show"} {positives.length} positive insight{positives.length > 1 ? "s" : ""}
            </button>
            {showPos && positives.map((a, i) => <AlertCard key={i} alert={a} id={`pos-${i}`} expanded={!!expanded[`pos-${i}`]} onToggle={toggle} />)}
          </>
        )}

        {/* Metrics strip */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "0.75rem", marginTop: "1.25rem" }}>
          {metrics.map(item => {
            const color = item.good ? C.good : item.warn ? C.warn : C.bad;
            return (
              <Card key={item.label} style={{ padding: "0.9rem 1rem" }}>
                <p style={{ color: C.muted, fontSize: "0.72rem", margin: "0 0 0.25rem", fontWeight: "600", textTransform: "uppercase", letterSpacing: "0.4px" }}>{item.label}</p>
                <p style={{ fontWeight: "700", fontSize: "1rem", margin: 0, color }}>{item.val}</p>
              </Card>
            );
          })}
        </div>
      </>
    );
  };

  return (
    <PageShell
      title="AI Financial Insights"
      subtitle="Priority-ordered analysis of your financial health."
    >
      <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: "1.25rem" }}>
        <PrimaryBtn onClick={() => fetch(true)} disabled={refreshing}>
          {refreshing ? "Refreshing..." : "Refresh"}
        </PrimaryBtn>
      </div>
      {renderBody()}
    </PageShell>
  );
}
