import { useState } from "react";
import api from "../../services/api";
import useDashboard from "../../services/useDashboard";
import PageShell, { C, Card, SectionLabel, PrimaryBtn, FInput } from "../Dashboard/PageShell.jsx";

const fmtPct = (n) => (typeof n === "number" && isFinite(n) ? `${(n * 100).toFixed(1)}%` : "—");
const fmtMo  = (n, provided) => {
  if (provided === false || (provided !== true && n == null)) return "No data provided";
  if (typeof n === "number" && isFinite(n)) return `${n.toFixed(1)} months`;
  return "No data provided";
};
const fmtRs  = (n) => (typeof n === "number" && isFinite(n) ? `Rs.${Math.round(n).toLocaleString()}` : "—");
const scoreColor = (s) => s >= 70 ? C.good : s >= 40 ? C.warn : C.bad;

function MetricList({ snap }) {
  const rows = [
    { label: "Savings Rate",   value: fmtPct(snap?.metrics?.savingsRatio) },
    { label: "Debt-to-Income", value: fmtPct(snap?.metrics?.debtToIncome) },
    { label: "Emergency Fund", value: `${fmtMo(snap?.metrics?.emergencyFundMonths, snap?.metrics?.emergencyFundProvided)}${snap?.metrics?.emergencyFundProvided && snap?.metrics?.emergencyFundRupees != null ? ` (${fmtRs(snap.metrics.emergencyFundRupees)})` : ""}` },
    { label: "Investment Rate",value: fmtPct(snap?.metrics?.investmentRatio) },
  ];
  return (
    <div style={{ borderTop: `1px solid ${C.moss}22`, paddingTop: "0.75rem" }}>
      {rows.map(r => (
        <div key={r.label} style={{ display: "flex", justifyContent: "space-between", padding: "0.3rem 0" }}>
          <span style={{ color: C.muted, fontSize: "0.8rem" }}>{r.label}</span>
          <span style={{ fontWeight: "600", color: C.darkGreen, fontSize: "0.8rem" }}>{r.value}</span>
        </div>
      ))}
    </div>
  );
}

export default function WhatIfSimulator() {
  const { data, loading, error } = useDashboard();
  const [form, setForm]         = useState({ extraSavings: "", salaryIncrease: "", extraDebtPayment: "", extraInvestment: "" });
  const [result, setResult]     = useState(null);
  const [simLoading, setSimLoading] = useState(false);

  const health    = data?.financialHealth;
  const hasData   = health?.dataState === "complete";
  const metrics   = health?.metrics ?? {};

  const baseSnapshot = hasData ? {
    score: health.score, status: health.category, biggestWeakness: health.biggestWeakness,
    metrics: {
      savingsRatio: metrics.savingsRatio ?? 0,
      debtToIncome: metrics.debtToIncome ?? 0,
      emergencyFundMonths: metrics.emergencyFundMonths ?? null,
      emergencyFundRupees: metrics.emergencyFundRupees ?? null,
      emergencyFundProvided: metrics.emergencyFundProvided === true,
      investmentRatio: metrics.investmentRatio ?? 0,
    },
  } : null;

  const efKnown    = metrics.emergencyFundProvided === true && metrics.emergencyFundMonths != null;
  const ef         = efKnown ? metrics.emergencyFundMonths : null;
  const efCritical = efKnown && ef < 1;
  const efAtRisk   = efKnown && ef < 3;
  const efRupees   = efKnown
    ? (metrics.emergencyFundRupees != null ? Math.round(metrics.emergencyFundRupees) : Math.round(ef * (metrics.monthlyExpenses ?? 0)))
    : 0;
  const efTarget   = Math.round((metrics.monthlyExpenses ?? 0) * 3);
  const efGap      = efKnown ? Math.max(0, efTarget - efRupees) : 0;

  const handleRun = async (e) => {
    e.preventDefault();
    if (!hasData) return;
    setSimLoading(true); setResult(null);
    try {
      const { data: res } = await api.post("/simulator", {
        extraMonthlySavings: Number(form.extraSavings)     || 0,
        salaryIncrease:      Number(form.salaryIncrease)   || 0,
        extraDebtPayment:    Number(form.extraDebtPayment) || 0,
        extraInvestment:     Number(form.extraInvestment)  || 0,
      });
      setResult(res);
    } catch (err) { alert(err.response?.data?.message || "Simulation failed."); }
    finally { setSimLoading(false); }
  };

  if (loading) return <PageShell title="What-If Simulator"><p style={{ color: `${C.beige}66` }}>Loading...</p></PageShell>;
  if (error)   return <PageShell title="What-If Simulator"><Card><p style={{ color: C.bad }}>{error}</p></Card></PageShell>;
  if (!hasData) return (
    <PageShell title="What-If Simulator">
      <Card style={{ textAlign: "center", padding: "2.5rem" }}>
        <p style={{ color: C.muted }}>{health?.dataState === "partial_data" ? "Income data required. Add your monthly income first." : "No financial data found. Add income and expenses first."}</p>
      </Card>
    </PageShell>
  );

  const currentSnap = result?.current ?? baseSnapshot;

  return (
    <PageShell title="What-If Simulator" subtitle="Adjust financial inputs and instantly see how your score would change.">

      {/* Base data bar */}
      <div style={{ display: "flex", gap: "1rem", flexWrap: "wrap", background: `${C.beige}12`, padding: "0.75rem 1rem", borderRadius: "10px", marginBottom: "1.25rem", border: `1px solid ${C.moss}22` }}>
        {[
          { label: "Income",      value: fmtRs(metrics.monthlyIncome) },
          { label: "Expenses",    value: fmtRs(metrics.monthlyExpenses) },
          { label: "Debt EMI",    value: fmtRs(metrics.monthlyDebtPayment) },
          { label: "Investments", value: fmtRs(metrics.monthlyInvestments) },
        ].map(item => (
          <div key={item.label} style={{ whiteSpace: "nowrap" }}>
            <span style={{ color: C.muted, fontSize: "0.78rem" }}>{item.label}: </span>
            <strong style={{ color: C.beige, fontSize: "0.88rem" }}>{item.value}/mo</strong>
          </div>
        ))}
      </div>

      {efCritical && (
        <div style={{ background: `${C.bad}12`, border: `1px solid ${C.bad}44`, color: C.bad, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1.25rem", fontSize: "0.88rem", lineHeight: 1.7 }}>
          <strong>Emergency fund critically low ({ef.toFixed(1)} months, {fmtRs(efRupees)}).</strong> You need {fmtRs(efGap)} more to reach 3 months. Extra debt payments and investments are locked — use savings and salary inputs to build your emergency fund first.
        </div>
      )}

      {/* Form */}
      <Card style={{ marginBottom: "1.5rem" }}>
        <form onSubmit={handleRun}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: "0.75rem", marginBottom: "1rem" }}>
            {[
              { key: "extraSavings",     label: "Save more per month (Rs.)",       hint: "Reduces monthly expenses",                  disabled: false },
              { key: "salaryIncrease",   label: "Salary increase (Rs./month)",     hint: "Increases monthly income",                  disabled: false },
              { key: "extraDebtPayment", label: "Extra debt payment (Rs./month)",  hint: efCritical ? null : "Added on top of EMIs",  disabled: efCritical, lock: efCritical ? `Locked — build EF to 1 month first (gap: ${fmtRs(efGap)})` : null },
              { key: "extraInvestment",  label: "Invest more per month (Rs.)",     hint: efCritical ? null : efAtRisk ? "EF below 3 months — consider splitting with EF" : "Added to monthly investments", disabled: efCritical, lock: efCritical ? `Locked — EF critically low (${ef.toFixed(1)} months). Need ${fmtRs(efGap)} more before investing.` : null },
            ].map(f => (
              <div key={f.key}>
                <FInput label={f.label} type="number" min="0" placeholder={f.disabled ? "Not available" : "e.g. 5000"}
                  value={f.disabled ? "" : form[f.key]}
                  onChange={e => !f.disabled && setForm({ ...form, [f.key]: e.target.value })} />
                {f.lock
                  ? <span style={{ display: "block", color: C.bad, fontSize: "0.72rem", marginTop: "0.25rem", fontWeight: "600" }}>{f.lock}</span>
                  : f.hint && <span style={{ display: "block", color: C.muted, fontSize: "0.72rem", marginTop: "0.25rem" }}>{f.hint}</span>
                }
              </div>
            ))}
          </div>
          <PrimaryBtn disabled={simLoading}>{simLoading ? "Simulating..." : "Run Simulation"}</PrimaryBtn>
        </form>
      </Card>

      {/* Score comparison */}
      <div style={{ display: "flex", gap: "1.25rem", alignItems: "flex-start", marginBottom: "1.5rem", flexWrap: "wrap" }}>
        <Card style={{ flex: 1, minWidth: "220px", borderTop: `4px solid ${C.muted}` }}>
          <p style={{ color: C.muted, fontSize: "0.72rem", textTransform: "uppercase", letterSpacing: "0.5px", margin: "0 0 0.5rem" }}>Current</p>
          <p style={{ fontSize: "3rem", fontWeight: "800", margin: 0, lineHeight: 1, color: scoreColor(currentSnap.score) }}>{currentSnap.score}</p>
          <p style={{ fontWeight: "600", color: C.darkGreen, margin: "0.25rem 0 1rem" }}>{currentSnap.status}</p>
          <MetricList snap={currentSnap} />
          {currentSnap.biggestWeakness && <p style={{ fontSize: "0.75rem", color: C.warn, marginTop: "0.75rem", background: `${C.warn}12`, padding: "0.35rem 0.6rem", borderRadius: "6px" }}>Weakness: {currentSnap.biggestWeakness}</p>}
        </Card>

        <div style={{ fontSize: "1.8rem", color: `${C.beige}44`, flexShrink: 0, alignSelf: "center" }}>→</div>

        <Card style={{ flex: 1, minWidth: "220px", borderTop: `4px solid ${result ? (result.scoreDiff > 0 ? C.good : result.scoreDiff < 0 ? C.bad : C.muted) : `${C.beige}33`}` }}>
          <p style={{ color: C.muted, fontSize: "0.72rem", textTransform: "uppercase", letterSpacing: "0.5px", margin: "0 0 0.5rem" }}>After Changes</p>
          {result ? (
            <>
              <p style={{ fontSize: "3rem", fontWeight: "800", margin: 0, lineHeight: 1, color: scoreColor(result.simulated.score) }}>{result.simulated.score}</p>
              <p style={{ fontWeight: "600", color: C.darkGreen, margin: "0.25rem 0 1rem" }}>{result.simulated.status}</p>
              <MetricList snap={result.simulated} />
              <div style={{ marginTop: "1rem", padding: "0.4rem 0.8rem", borderRadius: "8px", fontWeight: "700", fontSize: "1rem", display: "inline-block", background: result.scoreDiff > 0 ? `${C.good}18` : result.scoreDiff < 0 ? `${C.bad}18` : `${C.muted}18`, color: result.scoreDiff > 0 ? C.good : result.scoreDiff < 0 ? C.bad : C.muted }}>
                {result.scoreDiff > 0 ? "+" : ""}{result.scoreDiff} points
              </div>
            </>
          ) : (
            <p style={{ color: C.muted, fontSize: "0.88rem", marginTop: "2rem", textAlign: "center" }}>Run a simulation to see results.</p>
          )}
        </Card>
      </div>

      {result && (
        <>
          {result.warnings?.length > 0 && (
            <div style={{ background: `${C.warn}12`, border: `1px solid ${C.warn}44`, color: C.warn, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1.25rem", fontSize: "0.88rem", lineHeight: 1.6 }}>
              {result.warnings.map((w, i) => <p key={i} style={{ margin: i > 0 ? "0.5rem 0 0" : 0 }}>{w}</p>)}
            </div>
          )}

          {result.postWeakness && (
            <div style={{ background: `${C.warn}0f`, border: `1px solid ${C.warn}33`, color: C.warn, padding: "0.75rem 1.25rem", borderRadius: "10px", marginBottom: "1rem", fontSize: "0.86rem" }}>
              Next weakness to address: <strong>{result.postWeakness}</strong>
            </div>
          )}

          <div style={{ background: `${C.moss}12`, border: `1px solid ${C.moss}44`, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1.5rem" }}>
            <p style={{ color: C.moss, fontWeight: "600", margin: 0, fontSize: "0.95rem" }}>{result.verdict}</p>
          </div>

          {result.explanations?.length > 0 && (
            <Card style={{ marginBottom: "1.25rem" }}>
              <SectionLabel>What Changed</SectionLabel>
              {result.explanations.map((e, i) => <p key={i} style={{ color: C.darkGreen, fontSize: "0.88rem", padding: "0.3rem 0", borderBottom: `1px solid ${C.moss}15`, margin: 0 }}>{e}</p>)}
            </Card>
          )}

          {result.scoreBreakdown?.length > 0 && (
            <Card style={{ marginBottom: "1.25rem" }}>
              <SectionLabel>Score Component Changes</SectionLabel>
              {result.scoreBreakdown.map((c, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0.35rem 0", borderBottom: `1px solid ${C.moss}15` }}>
                  <span style={{ color: C.darkGreen, fontSize: "0.86rem" }}>{c.label} <span style={{ color: C.muted, fontSize: "0.72rem" }}>(weight {c.weight}%)</span></span>
                  <span style={{ fontWeight: "700", fontSize: "0.86rem", color: c.pointsDiff > 0 ? C.good : C.bad }}>{c.pointsDiff > 0 ? "+" : ""}{c.pointsDiff} pts</span>
                </div>
              ))}
            </Card>
          )}

          {result.surplusInsight && <div style={{ background: `${C.good}12`, border: `1px solid ${C.good}44`, color: C.good, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1.25rem", fontSize: "0.88rem", lineHeight: 1.6 }}><strong>Surplus Opportunity:</strong> {result.surplusInsight}</div>}
          {result.strategy       && <div style={{ background: `${C.moss}12`, border: `1px solid ${C.moss}44`, color: C.moss, padding: "1rem 1.25rem", borderRadius: "10px", marginBottom: "1.25rem", fontSize: "0.88rem", lineHeight: 1.6 }}><strong>Next Step:</strong> {result.strategy}</div>}

          <Card>
            <SectionLabel>12-Month Projections</SectionLabel>
            <div style={{ display: "flex", gap: "1rem", flexWrap: "wrap" }}>
              {[
                { label: "Free Cash Flow (after all outflows)", value: fmtRs(result.projections.monthlyCashFlow) },
                { label: "Projected Free Cash (12 months)",     value: fmtRs(result.projections.projectedSavings12Months) },
                result.projections.debtFreeInMonths ? { label: "Debt-Free In", value: `${result.projections.debtFreeInMonths} months` } : null,
              ].filter(Boolean).map(s => (
                <div key={s.label} style={{ flex: 1, minWidth: "140px", background: `${C.darkGreen}08`, padding: "0.75rem", borderRadius: "8px" }}>
                  <p style={{ color: C.muted, fontSize: "0.72rem", margin: 0 }}>{s.label}</p>
                  <p style={{ fontWeight: "700", color: C.darkGreen, margin: "0.25rem 0 0" }}>{s.value}</p>
                </div>
              ))}
            </div>
          </Card>
        </>
      )}
    </PageShell>
  );
}
